import{_ as a,c as n,o as s,a1 as i}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Optimización de Contexto: Ejecución Dividida por Sesiones | Tutorial de Agent App Factory","description":"Aprende a usar el comando factory continue para ahorrar Tokens, creando nuevas sesiones en cada fase. Mediante la ejecución dividida por sesiones, cada fase disfruta de un contexto limpio, reduciendo significativamente los costos de uso. Este tutorial cubre estrategias de aislamiento de contexto, mecanismos de recuperación de estado y mejores prácticas, ayudándote a dominar las técnicas de optimización de Tokens.","frontmatter":{"title":"Optimización de Contexto: Ejecución Dividida por Sesiones | Tutorial de Agent App Factory","sidebarTitle":"Optimización de Contexto","subtitle":"Optimización de Contexto: Ejecución Dividida por Sesiones","description":"Aprende a usar el comando factory continue para ahorrar Tokens, creando nuevas sesiones en cada fase. Mediante la ejecución dividida por sesiones, cada fase disfruta de un contexto limpio, reduciendo significativamente los costos de uso. Este tutorial cubre estrategias de aislamiento de contexto, mecanismos de recuperación de estado y mejores prácticas, ayudándote a dominar las técnicas de optimización de Tokens.","tags":["Avanzado","Optimización de Rendimiento","Ahorro de Tokens"],"prerequisite":["start-getting-started","start-pipeline-overview"],"order":160},"headers":[],"relativePath":"es/hyz1992/agent-app-factory/advanced/context-optimization/index.md","filePath":"es/hyz1992/agent-app-factory/advanced/context-optimization/index.md"}'),o={name:"es/hyz1992/agent-app-factory/advanced/context-optimization/index.md"};function t(r,e,c,l,d,p){return s(),n("div",null,[...e[0]||(e[0]=[i(`<h1 id="optimizacion-de-contexto-ejecucion-dividida-por-sesiones" tabindex="-1">Optimización de Contexto: Ejecución Dividida por Sesiones <a class="header-anchor" href="#optimizacion-de-contexto-ejecucion-dividida-por-sesiones" aria-label="Permalink to &quot;Optimización de Contexto: Ejecución Dividida por Sesiones&quot;">​</a></h1><h2 id="lo-que-aprenderas-en-esta-leccion" tabindex="-1">Lo Que Aprenderás en Esta Lección <a class="header-anchor" href="#lo-que-aprenderas-en-esta-leccion" aria-label="Permalink to &quot;Lo Que Aprenderás en Esta Lección&quot;">​</a></h2><ul><li>Usar el comando <code>factory continue</code> para continuar el pipeline en una nueva sesión</li><li>Comprender las ventajas de que cada fase tenga un contexto limpio e independiente</li><li>Dominar los métodos para reducir drásticamente el consumo de Tokens</li><li>Soportar la recuperación tras interrupciones, permitiendo pausar y reanudar en cualquier momento</li></ul><h2 id="tu-situacion-actual" tabindex="-1">Tu Situación Actual <a class="header-anchor" href="#tu-situacion-actual" aria-label="Permalink to &quot;Tu Situación Actual&quot;">​</a></h2><p>Cuando ejecutas el pipeline completo de 7 fases en un asistente de IA (como Claude Code), puedes encontrarte con estos problemas:</p><ul><li><strong>Tokens cada vez más consumidos</strong>: A medida que se acumula la conversación, el contexto se vuelve más largo y cada fase debe cargar todo el contenido de las fases anteriores</li><li><strong>Costos cada vez más altos</strong>: Una conversación larga significa más Tokens de entrada, y los costos aumentan linealmente</li><li><strong>Respuestas más lentas</strong>: Un contexto excesivamente largo puede incrementar el tiempo de respuesta</li><li><strong>Difícil de recuperar</strong>: Si una fase falla, reiniciar requiere recargar una gran cantidad de contexto</li></ul><div class="tip custom-block"><p class="custom-block-title">Problema Fundamental</p><p>La acumulación de contexto en conversaciones largas es una característica inherente de los asistentes de IA, pero podemos evitar este problema mediante la &quot;ejecución dividida por sesiones&quot;.</p></div><h2 id="cuando-usar-esta-tecnica" tabindex="-1">Cuándo Usar Esta Técnica <a class="header-anchor" href="#cuando-usar-esta-tecnica" aria-label="Permalink to &quot;Cuándo Usar Esta Técnica&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Escenario</th><th>¿Usar Ejecución Dividida?</th><th>Razón</th></tr></thead><tbody><tr><td>Ejecutar el pipeline completo de 7 fases</td><td>✅ Altamente Recomendado</td><td>Cada Token es valioso</td></tr><tr><td>Ejecutar solo 1-2 fases</td><td>⚠️ Opcional</td><td>El contexto es corto, no siempre es necesario</td></tr><tr><td>Depurar una fase específica</td><td>⚠️ Opcional</td><td>Reintentar frecuentemente puede aumentar el costo de cambio de sesión</td></tr><tr><td>Recuperar tras interrupción prolongada</td><td>✅ Obligatorio</td><td>Evita cargar contexto obsoleto</td></tr></tbody></table><h2 id="concepto-central" tabindex="-1">Concepto Central <a class="header-anchor" href="#concepto-central" aria-label="Permalink to &quot;Concepto Central&quot;">​</a></h2><p>Agent App Factory soporta la <strong>ejecución dividida por sesiones</strong>, cuya idea central es:</p><p><strong>Después de que termina cada fase, usar una nueva sesión para ejecutar la siguiente fase.</strong></p><p>Los beneficios de hacerlo así:</p><ol><li><strong>Contexto Limpio</strong>: Cada fase solo carga los archivos de entrada necesarios, sin depender del historial de conversación</li><li><strong>Ahorro de Tokens</strong>: Evita repetir todo el contenido de fases anteriores en cada interacción</li><li><strong>Recuperabilidad</strong>: Se puede interrumpir en cualquier momento y continuar después con una nueva sesión sin perder progreso</li><li><strong>Compatibilidad Multiplataforma</strong>: Aplicable a todos los asistentes de IA (Claude Code, OpenCode, Cursor, etc.)</li></ol><h3 id="estrategia-de-aislamiento-de-contexto" tabindex="-1">Estrategia de Aislamiento de Contexto <a class="header-anchor" href="#estrategia-de-aislamiento-de-contexto" aria-label="Permalink to &quot;Estrategia de Aislamiento de Contexto&quot;">​</a></h3><p>Para lograr la ejecución dividida por sesiones, Agent App Factory adopta una <strong>estrategia de aislamiento de contexto</strong>:</p><div class="info custom-block"><p class="custom-block-title">¿Qué es el Aislamiento de Contexto?</p><p>El aislamiento de contexto significa que cada Agent solo depende de archivos de entrada, no del historial de conversación. Sin importar qué haya ocurrido anteriormente, el Agent solo lee información de los archivos de entrada especificados.</p></div><p>Cuando cada Agent se ejecuta:</p><ul><li>✅ <strong>Solo lee</strong> los archivos <code>inputs</code> definidos en <code>pipeline.yaml</code></li><li>❌ <strong>No usa</strong> ninguna &quot;memoria&quot; del historial de conversación</li><li>❌ <strong>No asume</strong> saber qué ocurrió en fases anteriores</li></ul><p>Por ejemplo, cuando se ejecuta el Tech Agent:</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[Tech Agent] --&gt; B[Lee artifacts/prd/prd.md]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[Genera artifacts/tech/tech.md]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[Actualiza .factory/state.json]</span></span></code></pre></div><p>El Tech Agent solo se preocupa por <code>artifacts/prd/prd.md</code>, no piensa en &quot;qué aplicación quería construir el usuario&quot;. Toda la información proviene de los archivos de entrada.</p><h3 id="mecanismo-de-recuperacion-de-estado" tabindex="-1">Mecanismo de Recuperación de Estado <a class="header-anchor" href="#mecanismo-de-recuperacion-de-estado" aria-label="Permalink to &quot;Mecanismo de Recuperación de Estado&quot;">​</a></h3><p>Cuando ejecutas <code>factory continue</code>, el sistema:</p><ol><li>Lee <code>.factory/state.json</code> para obtener el progreso actual</li><li>Lee <code>.factory/pipeline.yaml</code> para determinar la siguiente fase</li><li><strong>Solo carga los archivos de entrada necesarios para esa fase</strong></li><li>Inicia una nueva ventana del asistente de IA para continuar la ejecución</li></ol><p>El archivo de estado (<code>.factory/state.json</code>) es el &quot;centro de memoria&quot; de todo el sistema:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;version&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;status&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;waiting_for_confirmation&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;current_stage&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;tech&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;completed_stages&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;bootstrap&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;prd&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;last_updated&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2026-01-29T12:00:00Z&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Después de que cada fase se completa, el estado se actualiza en este archivo. Cuando se inicia una nueva sesión, simplemente leyendo este archivo se puede saber dónde se encuentra actualmente.</p><h2 id="🎒-preparativos-antes-de-comenzar" tabindex="-1">🎒 Preparativos Antes de Comenzar <a class="header-anchor" href="#🎒-preparativos-antes-de-comenzar" aria-label="Permalink to &quot;🎒 Preparativos Antes de Comenzar&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Verificación de Requisitos Previos</p><p>Antes de comenzar este tutorial, asegúrate de:</p><ul><li>[ ] Haber completado <a href="./../../start/getting-started/">Quick Start</a> e inicializado un proyecto Factory</li><li>[ ] Haber comprendido la <a href="./../../start/pipeline-overview/">Visión General del Pipeline de 7 Fases</a></li><li>[ ] Tener instalado Claude Code (u otro asistente de IA)</li></ul><p>Si aún no has completado estos requisitos previos, por favor hazlo antes de continuar.</p></div><h2 id="sigueme-paso-a-paso" tabindex="-1">Sígueme Paso a Paso <a class="header-anchor" href="#sigueme-paso-a-paso" aria-label="Permalink to &quot;Sígueme Paso a Paso&quot;">​</a></h2><p>Aprendamos a usar el comando <code>factory continue</code> a través de un escenario práctico.</p><h3 id="escenario" tabindex="-1">Escenario <a class="header-anchor" href="#escenario" aria-label="Permalink to &quot;Escenario&quot;">​</a></h3><p>Supongamos que estás ejecutando un pipeline de 7 fases, y actualmente has completado las fases <code>bootstrap</code> y <code>prd</code>, y estás esperando confirmación en la fase <code>ui</code>.</p><h3 id="paso-1-seleccionar-continuar-en-nueva-sesion-en-el-checkpoint" tabindex="-1">Paso 1: Seleccionar &quot;Continuar en Nueva Sesión&quot; en el Checkpoint <a class="header-anchor" href="#paso-1-seleccionar-continuar-en-nueva-sesion-en-el-checkpoint" aria-label="Permalink to &quot;Paso 1: Seleccionar &quot;Continuar en Nueva Sesión&quot; en el Checkpoint&quot;">​</a></h3><p>Cuando una fase se completa, el Scheduler Sisyphus muestra una tabla de opciones:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✓ ¡ui completado!</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Entregables generados:</span></span>
<span class="line"><span>- artifacts/ui/ui.schema.yaml</span></span>
<span class="line"><span>- artifacts/ui/preview.web/index.html</span></span>
<span class="line"><span>- artifacts/ui/preview.web/styles.css</span></span>
<span class="line"><span>- artifacts/ui/preview.web/app.js</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  📋 Por favor seleccione la siguiente acción               │</span></span>
<span class="line"><span>│  Ingrese el número de opción (1-5), luego presione Enter   │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌──────┬──────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ Opc. │ Descripción                                           │</span></span>
<span class="line"><span>├──────┼──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  1   │ Continuar a la siguiente fase (misma sesión)          │</span></span>
<span class="line"><span>│      │ Continuaré ejecutando la fase tech                    │</span></span>
<span class="line"><span>├──────┼──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  2   │ Continuar en nueva sesión ⭐ Opción recomendada, ahorra Tokens │</span></span>
<span class="line"><span>│      │ Ejecutar en nueva ventana de terminal: factory continue│</span></span>
<span class="line"><span>│      │ (Se iniciará automáticamente una nueva ventana de Claude Code y continuará el pipeline) │</span></span>
<span class="line"><span>├──────┼──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  3   │ Re-ejecutar esta fase                                  │</span></span>
<span class="line"><span>│      │ Re-ejecutar la fase ui                               │</span></span>
<span class="line"><span>├──────┼──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  4   │ Modificar entregables y re-ejecutar                   │</span></span>
<span class="line"><span>│      │ Modificar artifacts/prd/prd.md y re-ejecutar            │</span></span>
<span class="line"><span>├──────┼──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  5   │ Pausar pipeline                                         │</span></span>
<span class="line"><span>│      │ Guardar progreso actual, continuar más tarde           │</span></span>
<span class="line"><span>└──────┴──────────────────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>💡 Sugerencia: Ingrese un número entre 1-5, luego presione Enter para confirmar su selección</span></span></code></pre></div><p><strong>Deberías ver</strong>:</p><ul><li>La opción 2 marcada como &quot;⭐ Opción recomendada, ahorra Tokens&quot;</li></ul><p>En la sesión actual, podemos seleccionar la opción 5 (pausar pipeline), y luego ejecutar <code>factory continue</code> en una nueva ventana de terminal.</p><p><strong>¿Por qué?</strong></p><ul><li>La opción 1 es &quot;Continuar a la siguiente fase (misma sesión)&quot;, que continuará en la sesión actual y el contexto se acumulará</li><li>La opción 2 es &quot;Continuar en nueva sesión&quot;, que ejecutará la siguiente fase con un contexto limpio y nuevo, <strong>ahorrando Tokens</strong></li><li>La opción 5 es &quot;Pausar pipeline&quot;, que guardará el progreso actual y luego se puede reanudar con <code>factory continue</code></li></ul><h3 id="paso-2-ejecutar-factory-continue-en-una-nueva-ventana-de-terminal" tabindex="-1">Paso 2: Ejecutar <code>factory continue</code> en una Nueva Ventana de Terminal <a class="header-anchor" href="#paso-2-ejecutar-factory-continue-en-una-nueva-ventana-de-terminal" aria-label="Permalink to &quot;Paso 2: Ejecutar \`factory continue\` en una Nueva Ventana de Terminal&quot;">​</a></h3><p>Abre una nueva ventana de terminal (o pestaña), navega al directorio de tu proyecto y ejecuta:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">factory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> continue</span></span></code></pre></div><p><strong>Deberías ver</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agent Factory - Continuar en Nueva Sesión</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Estado del Pipeline:</span></span>
<span class="line"><span>────────────────────────────────────────</span></span>
<span class="line"><span>Proyecto: my-awesome-app</span></span>
<span class="line"><span>Estado: Waiting</span></span>
<span class="line"><span>Fase Actual: tech</span></span>
<span class="line"><span>Completadas: bootstrap, prd</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Iniciando nueva sesión de Claude Code...</span></span>
<span class="line"><span>✓ Nueva ventana de Claude Code iniciada</span></span>
<span class="line"><span>  (Por favor espera a que se abra la ventana)</span></span></code></pre></div><p><strong>Lo que ocurrió</strong>:</p><ol><li>El comando <code>factory continue</code> leyó <code>.factory/state.json</code> para conocer el estado actual</li><li>Mostró la información de estado del proyecto actual</li><li>Inició automáticamente una nueva ventana de Claude Code y pasó la instrucción &quot;por favor continúa ejecutando el pipeline&quot;</li><li>La nueva ventana continuará automáticamente desde la fase <code>tech</code></li></ol><h3 id="paso-3-continuar-ejecutando-en-la-nueva-ventana" tabindex="-1">Paso 3: Continuar Ejecutando en la Nueva Ventana <a class="header-anchor" href="#paso-3-continuar-ejecutando-en-la-nueva-ventana" aria-label="Permalink to &quot;Paso 3: Continuar Ejecutando en la Nueva Ventana&quot;">​</a></h3><p>Una vez iniciada la nueva ventana de Claude Code, verás una nueva conversación, pero el estado se ha restaurado desde el checkpoint guardado anteriormente.</p><p>En la nueva sesión, el Agent:</p><ol><li>Lee <code>.factory/state.json</code> para obtener la fase actual</li><li>Lee <code>.factory/pipeline.yaml</code> para determinar las entradas y salidas de esa fase</li><li><strong>Solo carga los archivos de entrada necesarios para esa fase</strong> (por ejemplo, <code>artifacts/prd/prd.md</code>)</li><li>Ejecuta las tareas de esa fase</li></ol><p><strong>Punto Clave</strong>:</p><ul><li>No hay historial de conversación de fases anteriores en la nueva sesión</li><li>El Agent solo lee información de los archivos de entrada, no depende de la &quot;memoria&quot;</li><li>Esto es la manifestación del <strong>aislamiento de contexto</strong></li></ul><h3 id="paso-4-verificar-el-aislamiento-de-contexto" tabindex="-1">Paso 4: Verificar el Aislamiento de Contexto <a class="header-anchor" href="#paso-4-verificar-el-aislamiento-de-contexto" aria-label="Permalink to &quot;Paso 4: Verificar el Aislamiento de Contexto&quot;">​</a></h3><p>Para verificar si el aislamiento de contexto está funcionando, puedes intentar preguntarle al Agent en la nueva sesión:</p><p>&quot;¿Sabes qué hizo la fase bootstrap?&quot;</p><p>Si el aislamiento de contexto está funcionando, el Agent responderá algo como:</p><p>&quot;Primero necesito revisar los archivos relevantes para entender el trabajo anterior. Permíteme leer...&quot;</p><p>Luego intentará leer <code>input/idea.md</code> u otros archivos para obtener información, en lugar de &quot;recordar&quot; directamente del historial de conversación.</p><p><strong>Checkpoint ✅</strong></p><ul><li>Nueva sesión iniciada correctamente</li><li>Se muestra el estado correcto del proyecto</li><li>El Agent solo depende de archivos de entrada, no del historial de conversación</li></ul><h3 id="paso-5-continuar-ejecutando-las-fases-restantes" tabindex="-1">Paso 5: Continuar Ejecutando las Fases Restantes <a class="header-anchor" href="#paso-5-continuar-ejecutando-las-fases-restantes" aria-label="Permalink to &quot;Paso 5: Continuar Ejecutando las Fases Restantes&quot;">​</a></h3><p>Después de que cada fase se complete, puedes elegir:</p><ul><li>Continuar en la sesión actual (opción 1) - Aplicable para flujos cortos</li><li><strong>Continuar en nueva sesión (opción 2)</strong> - <strong>Recomendado, ahorra Tokens</strong></li><li>Pausar pipeline (opción 5) - Ejecutar <code>factory continue</code> después</li></ul><p>Para el pipeline completo de 7 fases, se recomienda usar &quot;Continuar en nueva sesión&quot; para cada fase, de esta manera:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>bootstrap (sesión 1) → prd (sesión 2) → ui (sesión 3) → tech (sesión 4)</span></span>
<span class="line"><span>→ code (sesión 5) → validation (sesión 6) → preview (sesión 7)</span></span></code></pre></div><p>Cada sesión es limpia y no necesita cargar el contenido de todas las fases anteriores.</p><h2 id="alertas-de-posibles-errores" tabindex="-1">Alertas de Posibles Errores <a class="header-anchor" href="#alertas-de-posibles-errores" aria-label="Permalink to &quot;Alertas de Posibles Errores&quot;">​</a></h2><h3 id="error-1-olvidar-ejecutar-factory-continue" tabindex="-1">Error 1: Olvidar Ejecutar <code>factory continue</code> <a class="header-anchor" href="#error-1-olvidar-ejecutar-factory-continue" aria-label="Permalink to &quot;Error 1: Olvidar Ejecutar \`factory continue\`&quot;">​</a></h3><p><strong>Práctica Incorrecta</strong>:</p><ul><li>Comenzar la siguiente fase directamente en la sesión antigua</li><li>O abrir una nueva ventana de Claude Code directamente sin ejecutar <code>factory continue</code></li></ul><p><strong>Práctica Correcta</strong>:</p><ul><li>Siempre usa el comando <code>factory continue</code> para iniciar una nueva sesión</li><li>Este comando lee automáticamente el estado y pasa las instrucciones correctas</li></ul><h3 id="error-2-recargar-archivos-historicos-en-la-nueva-sesion" tabindex="-1">Error 2: Recargar Archivos Históricos en la Nueva Sesión <a class="header-anchor" href="#error-2-recargar-archivos-historicos-en-la-nueva-sesion" aria-label="Permalink to &quot;Error 2: Recargar Archivos Históricos en la Nueva Sesión&quot;">​</a></h3><p><strong>Práctica Incorrecta</strong>:</p><ul><li>Pedir manualmente a la IA que lea los entregables de fases anteriores en la nueva sesión</li><li>Pensar que la IA &quot;debería saber&quot; lo que ocurrió antes</li></ul><p><strong>Práctica Correcta</strong>:</p><ul><li>Confía en el mecanismo de aislamiento de contexto, el Agent leerá automáticamente la información de los archivos de entrada</li><li>Solo proporciona los archivos de entrada necesarios para esa fase</li></ul><h3 id="error-3-usar-factory-continue-en-multiples-proyectos" tabindex="-1">Error 3: Usar <code>factory continue</code> en Múltiples Proyectos <a class="header-anchor" href="#error-3-usar-factory-continue-en-multiples-proyectos" aria-label="Permalink to &quot;Error 3: Usar \`factory continue\` en Múltiples Proyectos&quot;">​</a></h3><p><strong>Práctica Incorrecta</strong>:</p><ul><li>Ejecutar <code>factory continue</code> en el Proyecto A, pero el directorio actual es el Proyecto B</li></ul><p><strong>Práctica Correcta</strong>:</p><ul><li><code>factory continue</code> verifica si el directorio actual es un proyecto Factory</li><li>Si no lo es, te pedirá que ejecutes <code>factory init</code> primero</li></ul><h3 id="error-4-no-usar-factory-continue-despues-de-modificar-entregables" tabindex="-1">Error 4: No Usar <code>factory continue</code> Después de Modificar Entregables <a class="header-anchor" href="#error-4-no-usar-factory-continue-despues-de-modificar-entregables" aria-label="Permalink to &quot;Error 4: No Usar \`factory continue\` Después de Modificar Entregables&quot;">​</a></h3><p><strong>Escenario</strong>:</p><ul><li>Después de completar una fase, modificas manualmente el entregable (como el PRD)</li><li>Quieres continuar ejecutando la siguiente fase</li></ul><p><strong>Práctica Correcta</strong>:</p><ul><li>Ejecutar <code>factory run</code> (reiniciará desde la fase especificada)</li><li>O ejecutar <code>factory continue</code> (continuará desde el checkpoint actual)</li><li>No continúes directamente en la sesión antigua, porque el contexto puede ser inconsistente</li></ul><h2 id="resumen-de-esta-leccion" tabindex="-1">Resumen de Esta Lección <a class="header-anchor" href="#resumen-de-esta-leccion" aria-label="Permalink to &quot;Resumen de Esta Lección&quot;">​</a></h2><p>En esta lección aprendimos a usar el comando <code>factory continue</code> para la ejecución dividida por sesiones:</p><h3 id="puntos-clave" tabindex="-1">Puntos Clave <a class="header-anchor" href="#puntos-clave" aria-label="Permalink to &quot;Puntos Clave&quot;">​</a></h3><ol><li><strong>Ejecución Dividida por Sesiones</strong>: Después de que cada fase se completa, usar una nueva sesión para ejecutar la siguiente fase</li><li><strong>Aislamiento de Contexto</strong>: El Agent solo depende de archivos de entrada, no del historial de conversación</li><li><strong>Recuperación de Estado</strong>: <code>.factory/state.json</code> registra el progreso actual, las nuevas sesiones pueden recuperar el estado</li><li><strong>Ahorro de Tokens</strong>: Evita cargar un contexto excesivamente largo, reduciendo significativamente los costos</li></ol><h3 id="referencia-rapida-de-comandos" tabindex="-1">Referencia Rápida de Comandos <a class="header-anchor" href="#referencia-rapida-de-comandos" aria-label="Permalink to &quot;Referencia Rápida de Comandos&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Comando</th><th>Función</th><th>Escenario de Uso</th></tr></thead><tbody><tr><td><code>factory continue</code></td><td>Continuar el pipeline en nueva sesión</td><td>Después de que cada fase se complete</td></tr><tr><td><code>factory run</code></td><td>Ejecutar el pipeline en la sesión actual</td><td>Primera ejecución o depuración</td></tr><tr><td><code>factory status</code></td><td>Ver el estado actual del proyecto</td><td>Entender el progreso</td></tr></tbody></table><h3 id="mejores-practicas" tabindex="-1">Mejores Prácticas <a class="header-anchor" href="#mejores-practicas" aria-label="Permalink to &quot;Mejores Prácticas&quot;">​</a></h3><ul><li>✅ Al ejecutar el pipeline completo de 7 fases, usar <code>factory continue</code> en cada fase</li><li>✅ En el checkpoint seleccionar &quot;Continuar en nueva sesión&quot; (opción 2)</li><li>✅ Confiar en el mecanismo de aislamiento de contexto, no cargar manualmente archivos históricos</li><li>✅ Usar <code>factory status</code> para verificar el progreso del proyecto</li></ul><h2 id="vista-previa-de-la-siguiente-leccion" tabindex="-1">Vista Previa de la Siguiente Lección <a class="header-anchor" href="#vista-previa-de-la-siguiente-leccion" aria-label="Permalink to &quot;Vista Previa de la Siguiente Lección&quot;">​</a></h2><blockquote><p>En la siguiente lección aprenderemos <strong><a href="./../security-permissions/">Mecanismos de Permisos y Seguridad</a></strong>.</p><p>Aprenderás:</p><ul><li>Cómo la matriz de límites de capacidades previene que los Agentes excedan sus permisos</li><li>Mecanismos de manejo de excesos de permisos y aislamiento de entregables no confiables</li><li>Puntos de verificación de seguridad y procesos de verificación de permisos</li><li>Cómo configurar los archivos de permisos de Claude Code</li></ul></blockquote><p>Esta lección te ayudará a comprender los mecanismos de seguridad de Agent App Factory, asegurando que cada Agent solo lea y escriba archivos en directorios autorizados.</p><hr><h2 id="apendice-referencia-del-codigo-fuente" tabindex="-1">Apéndice: Referencia del Código Fuente <a class="header-anchor" href="#apendice-referencia-del-codigo-fuente" aria-label="Permalink to &quot;Apéndice: Referencia del Código Fuente&quot;">​</a></h2><details><summary><strong>Haz clic para ver la ubicación del código fuente</strong></summary><blockquote><p>Última actualización: 2026-01-29</p></blockquote><table tabindex="0"><thead><tr><th>Función</th><th>Ruta del Archivo</th><th>Número de Línea</th></tr></thead><tbody><tr><td>Comando factory continue</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/cli/commands/continue.js" target="_blank" rel="noreferrer"><code>cli/commands/continue.js</code></a></td><td>1-144</td></tr><tr><td>Optimización de contexto del scheduler</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/agents/orchestrator.checkpoint.md" target="_blank" rel="noreferrer"><code>agents/orchestrator.checkpoint.md</code></a></td><td>113-154</td></tr><tr><td>Estrategia de aislamiento de contexto</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/context-isolation.md" target="_blank" rel="noreferrer"><code>policies/context-isolation.md</code></a></td><td>1-64</td></tr></tbody></table><p><strong>Funciones Clave</strong>:</p><ul><li><code>launchClaudeCode(projectDir, nextStage, completedStages)</code>: Inicia una nueva ventana de Claude Code</li><li><code>commandExists(cmd)</code>: Verifica si un comando está disponible</li><li><code>module.exports(projectDir)</code>: Función principal del comando <code>factory continue</code></li></ul><p><strong>Constantes Clave</strong>:</p><ul><li><code>state.json</code>: Ruta del archivo de estado (<code>.factory/state.json</code>)</li><li><code>pipeline.yaml</code>: Ruta del archivo de definición del pipeline (<code>.factory/pipeline.yaml</code>)</li><li><code>config.yaml</code>: Ruta del archivo de configuración del proyecto (<code>.factory/config.yaml</code>)</li></ul><p><strong>Reglas de Negocio Clave</strong>:</p><ul><li>BR-6-1: Cada fase disfruta de un contexto limpio independiente</li><li>BR-6-2: Usar el comando <code>factory continue</code> para continuar</li><li>BR-6-3: Solo cargar los archivos necesarios para la fase actual</li></ul></details>`,104)])])}const m=a(o,[["render",t]]);export{h as __pageData,m as default};
